// Custom local fetch wrapper to securely append the active session token to all backend API calls
const fetch = async (input: RequestInfo | URL, init?: RequestInit): Promise<Response> => {
  const token = localStorage.getItem("sehr_auth_token");
  let headers: HeadersInit = init?.headers || {};
  if (token) {
    if (headers instanceof Headers) {
      headers.set("Authorization", `Bearer ${token}`);
    } else if (Array.isArray(headers)) {
      const authIdx = headers.findIndex(h => h[0].toLowerCase() === "authorization");
      if (authIdx !== -1) {
        headers[authIdx] = ["Authorization", `Bearer ${token}`];
      } else {
        headers.push(["Authorization", `Bearer ${token}`]);
      }
    } else {
      headers = {
        ...headers,
        "Authorization": `Bearer ${token}`
      };
    }
  }
  return window.fetch(input, { ...init, headers });
};

interface PattiConfig {
  bgClass: string;
  borderClass: string;
  textColorClass: string;
  badgeBgClass: string;
  badgeTextClass: string;
  levelLabel: string;
  icon: string;
  sparkleColor: string;
}

const getPattiConfig = (level: number): PattiConfig => {
  if (level >= 80) {
    return {
      bgClass: "bg-gradient-to-r from-[#1f013d] via-[#3d0354] to-[#4d0c1d] border-[#ffd700] border shadow-[0_0_12px_rgba(234,179,8,0.4)]",
      borderClass: "border-[#ffd700]",
      textColorClass: "text-yellow-300 font-extrabold animate-ribbon-sparkle",
      badgeBgClass: "bg-gradient-to-r from-yellow-400 to-amber-500",
      badgeTextClass: "text-purple-950 font-black",
      levelLabel: "Mythic Emperor",
      icon: "👑",
      sparkleColor: "rgba(251, 191, 36, 0.4)"
    };
  } else if (level >= 60) {
    return {
      bgClass: "bg-gradient-to-r from-[#2a0410] via-[#520d23] to-[#2a0410] border-rose-500 border shadow-[0_0_10px_rgba(244,63,94,0.35)]",
      borderClass: "border-rose-500",
      textColorClass: "text-rose-300 font-black",
      badgeBgClass: "bg-rose-600",
      badgeTextClass: "text-white font-black",
      levelLabel: "Legendary Hero",
      icon: "🔥",
      sparkleColor: "rgba(244, 63, 94, 0.3)"
    };
  } else if (level >= 40) {
    return {
      bgClass: "bg-gradient-to-r from-[#031d2a] via-[#09353f] to-[#041a33] border-cyan-400 border shadow-[0_0_8px_rgba(34,211,238,0.3)]",
      borderClass: "border-cyan-400",
      textColorClass: "text-cyan-300 font-black",
      badgeBgClass: "bg-cyan-500",
      badgeTextClass: "text-slate-950 font-black",
      levelLabel: "Platinum Overlord",
      icon: "💎",
      sparkleColor: "rgba(34, 211, 238, 0.3)"
    };
  } else if (level >= 30) {
    return {
      bgClass: "bg-gradient-to-r from-[#281a04] via-[#4a320b] to-[#281a04] border-yellow-400 border shadow-[0_0_6px_rgba(251,191,36,0.2)]",
      borderClass: "border-yellow-400",
      textColorClass: "text-yellow-300 font-bold",
      badgeBgClass: "bg-yellow-400",
      badgeTextClass: "text-yellow-950 font-black",
      levelLabel: "Gold Elite",
      icon: "🌟",
      sparkleColor: "rgba(253, 224, 71, 0.3)"
    };
  } else if (level >= 20) {
    return {
      bgClass: "bg-gradient-to-r from-[#171b26] via-[#2a3040] to-[#171b26] border-slate-400 border",
      borderClass: "border-slate-400",
      textColorClass: "text-slate-300 font-semibold",
      badgeBgClass: "bg-slate-400",
      badgeTextClass: "text-slate-950 font-black",
      levelLabel: "Silver Star",
      icon: "🛡️",
      sparkleColor: "rgba(203, 213, 225, 0.2)"
    };
  } else {
    // Level 10-19: Bronze
    return {
      bgClass: "bg-gradient-to-r from-[#1f1207] via-[#3b210b] to-[#1f1207] border-[#aa6c39] border",
      borderClass: "border-[#aa6c39]",
      textColorClass: "text-orange-300 font-medium",
      badgeBgClass: "bg-[#aa6c39]",
      badgeTextClass: "text-white font-black",
      levelLabel: "Bronze Knight",
      icon: "⚔️",
      sparkleColor: "rgba(180, 83, 9, 0.2)"
    };
  }
};

