  const startKycCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ video: { width: 320, height: 240 } });
      setKycCameraStream(stream);
      if (kycVideoRef.current) {
        kycVideoRef.current.srcObject = stream;
        kycVideoRef.current.play().catch(err => console.log("Video play failed:", err));
      }
    } catch (err) {
      console.warn("Webcam blocked or unavailable, falling back to biometric scan simulation:", err);
    }
  };

