  const handleKycFileChange = (e: React.ChangeEvent<HTMLInputElement>, side: "front" | "back") => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        if (typeof reader.result === "string") {
          if (side === "front") {
            setKycFrontImage(reader.result);
          } else {
            setKycBackImage(reader.result);
          }
        }
      };
      reader.readAsDataURL(file);
    }
  };

  const runKycScan = () => {
    setKycScanning(true);
    setKycProgress(0);
    setKycScanSuccess(false);
    setKycScanMessage("Requesting device camera security access...");
    
    // Start camera stream (simulated if blocked)
    startKycCamera();

    let currentProgress = 0;
    const interval = setInterval(() => {
      currentProgress += 2;
      if (currentProgress > 100) {
        currentProgress = 100;
      }
      setKycProgress(currentProgress);

      if (currentProgress < 20) {
        setKycScanMessage("Initializing biometric scanning grid...");
      } else if (currentProgress < 45) {
        setKycScanMessage("Mapping facial landmarks (3D Mesh)... Hold still.");
      } else if (currentProgress < 70) {
        setKycScanMessage("Proving liveness detection... Please blink your eyes.");
      } else if (currentProgress < 90) {
        setKycScanMessage("Matching registration registry records (Pakistan Sim database)...");
      } else if (currentProgress < 100) {
        setKycScanMessage("Securing encrypted verification block...");
      } else {
        clearInterval(interval);
        setKycScanning(false);
        setKycScanSuccess(true);
        setKycScanMessage("Biometric Match Completed successfully! ✨");
        stopKycCamera();
      }
    }, 80); // 100% in 4 seconds
  };

