  // 🎵 Live Stream Music Controller Effects
  useEffect(() => {
    if (typeof window !== "undefined") {
      audioPlayerRef.current = new Audio();
    }
    return () => {
      if (audioPlayerRef.current) {
        audioPlayerRef.current.pause();
        audioPlayerRef.current = null;
      }
    };
  }, []);

  useEffect(() => {
    const player = audioPlayerRef.current;
    if (!player) return;

    if (clientView === "user-live" && userLiveActiveTrack) {
      if (player.src !== userLiveActiveTrack.url) {
        player.src = userLiveActiveTrack.url;
        player.load();
      }
      
      if (userLiveMusicPlaying) {
        player.play().catch(err => {
          console.warn("Audio play prevented or failed:", err);
          setUserLiveMusicPlaying(false);
        });
      } else {
        player.pause();
      }
    } else if (clientView === "live-room" && liveRoomActiveTrack) {
      if (player.src !== liveRoomActiveTrack.url) {
        player.src = liveRoomActiveTrack.url;
        player.load();
      }
      
      if (liveRoomMusicPlaying) {
        player.play().catch(err => {
          console.warn("Viewer Audio play failed:", err);
          setLiveRoomMusicPlaying(false);
        });
      } else {
        player.pause();
      }
    } else {
      player.pause();
    }
  }, [clientView, userLiveActiveTrack, userLiveMusicPlaying, liveRoomActiveTrack, liveRoomMusicPlaying]);

  useEffect(() => {
    const player = audioPlayerRef.current;
    if (player) {
      if (clientView === "user-live") {
        player.volume = userLiveMusicVolume;
      } else if (clientView === "live-room") {
        player.volume = liveRoomMusicVolume;
      }
    }
  }, [clientView, userLiveMusicVolume, liveRoomMusicVolume]);

  useEffect(() => {
    const player = audioPlayerRef.current;
    if (!player) return;

    const handleTimeUpdate = () => {
      if (player.duration) {
        setUserLiveMusicProgress((player.currentTime / player.duration) * 100);
      }
    };

    const handleEnded = () => {
      if (clientView === "user-live") {
        setUserLiveMusicPlaying(false);
        setUserLiveMusicProgress(0);
      } else if (clientView === "live-room") {
        // For viewers, let's auto-loop the background music to keep the room atmospheric!
        player.currentTime = 0;
        player.play().catch(() => setLiveRoomMusicPlaying(false));
      }
    };

    player.addEventListener("timeupdate", handleTimeUpdate);
    player.addEventListener("ended", handleEnded);

    return () => {
      player.removeEventListener("timeupdate", handleTimeUpdate);
      player.removeEventListener("ended", handleEnded);
    };
  }, [clientView, userLiveActiveTrack, liveRoomActiveTrack]);

