                                    const text = inputEl.value.trim();
                                    if (!text) return;

                                    // Add to current selection
                                    setSelectedProfileReel((prev: any) => prev ? { ...prev, comments: [...prev.comments, text] } : null);

                                    // Sync back to master list
                                    setProfileReels((prev: any) => {
                                      const tabKey = selectedProfileReel.tab as "uploaded" | "liked" | "saved" | "private";
                                      return {
                                        ...prev,
                                        [tabKey]: prev[tabKey].map((r: any) => r.id === selectedProfileReel.id ? { ...r, comments: [...r.comments, text] } : r)
                                      };
                                    });

                                    inputEl.value = "";
