                            { id: "effects", label: "Effects", icon: <Flame className={`w-3.5 h-3.5 ${prepShowEffectsSelector ? "text-pink-400 animate-pulse" : "text-white"}`} />, active: prepShowEffectsSelector, info: prepEffect },
                            { id: "flash", label: "Flash", icon: <Zap className={`w-3.5 h-3.5 ${prepFlash ? "text-yellow-400" : "text-white"}`} />, active: prepFlash, info: prepFlash ? "ON" : "OFF" },
                            { id: "timer", label: "Timer", icon: <Clock className={`w-3.5 h-3.5 ${prepTimer !== "Off" ? "text-purple-400" : "text-white"}`} />, active: prepTimer !== "Off", info: prepTimer },
                            { id: "mirror", label: "Mirror", icon: <Smartphone className={`w-3.5 h-3.5 ${prepMirror ? "text-cyan-400" : "text-white"}`} />, active: prepMirror, info: prepMirror ? "ON" : "OFF" },
                            { id: "hd", label: "HD", icon: <Tv className={`w-3.5 h-3.5 ${prepHd ? "text-green-400" : "text-white"}`} />, active: prepHd, info: prepHd ? "1080p" : "SD" },
                            { id: "settings", label: "Options", icon: <Settings className={`w-3.5 h-3.5 ${prepShowSettingsPanel ? "text-pink-400" : "text-white"}`} />, active: prepShowSettingsPanel, info: "Stream" }
